func productExceptSelf_v0(nums []int) []int { // Time out on online platforms (leetcode and goplayground)
	product := 1
	answer := make([]int, 0, len(nums))
	for i := 0; i < len(nums); i++ {
		for j := 0; j < len(nums); j++ {
			if j == i {
				continue
			}
			product *= nums[j]
		}
		answer = append(answer, product)
		product = 1
	}
	return answer
}

func productExceptSelf_v1(nums []int) []int { // 6ms with 10.3mb memory
	answer := make([]int, len(nums))
	prefixArr := make([]int, len(nums))
	postfixArr := make([]int, len(nums))

	prefix := 1
	postfix := 1
	for i, j := 0, len(nums)-1; i < len(nums) && j >= 0; i, j = i+1, j-1 {
		prefix *= nums[i]
		prefixArr[i] = prefix

		postfix *= nums[j]
		postfixArr[j] = postfix
	}
	// fill the output (answer) arrar
	prefixProduct := 1
	postfixProduct := 1
	for i := 0; i < len(nums); i++ {
		if i-1 < 0 {
			prefixProduct = 1
		} else {
			prefixProduct = prefixArr[i-1]
		}
		if i+1 > len(nums)-1 {
			postfixProduct = 1
		} else {
			postfixProduct = postfixArr[i+1]
		}
		answer[i] = prefixProduct * postfixProduct
	}
	return answer
}

func productExceptSelf_v2(nums []int) []int { // 33ms with 11.40MB memory
	answer := make([]int, len(nums))
	prefixArr := make([]int, len(nums))
	postfixArr := make([]int, len(nums))
	if len(nums) > 0 {
		prefixArr[0] = 1
		postfixArr[len(nums)-1] = 1
	}
	for i, j := 0, len(nums)-1; i < len(nums)-1 && j > 0; i, j = i+1, j-1 {
		prefixArr[i+1] = prefixArr[i] * nums[i]
		postfixArr[j-1] = postfixArr[j] * nums[j]
	}
	// fill the output (answer) arrar
	for i := 0; i < len(nums); i++ {
		answer[i] = prefixArr[i] * postfixArr[i]
	}
	return answer
}

/*
Question: does reading array at any index take more than reading a normal veriable?
Answer:
Yes, reading an array element (arr[i]) can take more time than reading a normal variable (x),
but the difference depends on several factors, including CPU caching, memory access patterns, and branch prediction.

Key Differences in Access Time

Normal Variable (int x)	Very fast (O(1)) – stored in registers or L1 cache
Array Element (arr[i])	Can be slightly slower – may require memory access


Why is Array Access Potentially Slower?

Cache Efficiency
CPU registers and L1 cache are much faster than RAM.
A normal variable (int x) is usually stored in registers → instant access.
An array (arr[i]) might be in L1/L2 cache (fast) or RAM (slow).

Memory Access Patterns
If an array is iterated sequentially, modern CPUs prefetch data efficiently, making access almost as fast as a normal variable.
If accesses are random (arr[i] with unpredictable i), cache misses occur → higher latency.
Pointer Arithmetic

Accessing arr[i] involves:
base_address + (i * sizeof(int))  // Requires multiplication & addition
A normal variable like int x = 5; does not need address calculations.

Branch Prediction & Pipelining
Loops iterating over an array can be optimized by CPUs.
However, if i is computed dynamically (arr[f(x)]), CPU may mispredict → slowdown.

When Does This Matter in Your Code?
If v1 and v2 store prefix and postfix in arrays, they might cause extra memory accesses.
Instead of using prefixArr[i] and postfixArr[i], storing values in simple variables (prefix, postfix) improves cache efficiency.
Example
✅ Fast (normal variable)
prefix := 1
for i := 0; i < len(nums); i++ {
    result[i] = prefix
    prefix *= nums[i]
}

❌ Slightly Slower (array access)
prefixArr[i+1] = prefixArr[i] * nums[i] // Extra memory load/store


Conclusion
Normal variable (x) is always faster than arr[i] because it uses registers/cache.
Sequential array access is fast, but random access can slow down due to cache misses.
Avoid unnecessary array reads/writes in performance-critical code.
Your v2 version is slower because it does more array accesses, causing extra CPU work.
*/

func productExceptSelf_v3(nums []int) []int { // 4ms with 10.82mb memory
	answer := make([]int, len(nums))
	prefix := 1
	for i := 0; i < len(nums); i++ {
		answer[i] = prefix
		prefix *= nums[i]
	}
	postfix := 1
	for j := len(nums) - 1; j >= 0; j-- {
		answer[j] *= postfix
		postfix *= nums[j]
	}
	return answer
}


